import { getAccount } from '@/api/Account';
import { getUserNotes, createNote } from '@/api/Note';
import { chatWithAI } from '@/api/AI';
import Sidebar from '@/components/Sidebar.vue';
import { useNotification } from '@/composables/useNotification';
export default {
  name: 'Dashboard',
  components: {
    Sidebar
  },
  setup() {
    const {
      showSuccess,
      showError,
      showInfo,
      showWarning
    } = useNotification();
    return {
      showSuccess,
      showError,
      showInfo,
      showWarning
    };
  },
  data() {
    return {
      userName: 'Loading...',
      userLevel: 1,
      userEmail: '',
      userId: null,
      recentNotes: [],
      loading: true,
      error: null,
      // Modal states
      showAudioModal: false,
      showYouTubeModal: false,
      showDocumentModal: false,
      showProcessingModal: false,
      // Audio recording
      isRecording: false,
      mediaRecorder: null,
      audioBlob: null,
      recordingTime: 0,
      recordingTimer: null,
      selectedAudioFile: null,
      isDragOver: false,
      // YouTube
      youtubeUrl: '',
      // Document upload
      selectedDocumentFile: null,
      isDragOverDoc: false,
      // Processing
      processingMessage: '',
      processingProgress: 0
    };
  },
  async mounted() {
    await this.loadUserData();
  },
  methods: {
    getParticleSize(index) {
      const sizes = ['small', 'medium', 'large'];
      return sizes[index % 3];
    },
    getParticleColor(index) {
      const colors = ['blue', 'purple', 'pink', 'cyan'];
      return colors[index % 4];
    },
    // Helper function to decode JWT token and get user ID
    getUserIdFromToken() {
      try {
        const token = localStorage.getItem('token');
        if (!token) return null;

        // Decode JWT token (simple base64 decode for payload)
        const payload = JSON.parse(atob(token.split('.')[1]));
        return payload.id;
      } catch (error) {
        console.error('Error decoding token:', error);
        this.showError('Error decoding authentication token');
        return null;
      }
    },
    async loadUserData() {
      try {
        this.loading = true;
        this.error = null;

        // Get user ID from JWT token
        const userId = this.getUserIdFromToken();
        if (!userId) {
          throw new Error('No valid user token found');
        }
        this.userId = userId;

        // Fetch user account data
        const accountData = await getAccount(userId);
        this.userName = accountData.username;
        this.userEmail = accountData.email;
        this.userLevel = accountData.currentLevel;

        // Fetch recent notes
        try {
          const notesData = await getUserNotes(userId);
          this.recentNotes = notesData.slice(0, 6).map(note => ({
            id: note._id,
            title: note.title,
            content: note.content,
            category: note.category,
            isFavorite: note.isFavorite,
            updatedAt: note.date_updated || note.updatedAt
          }));
        } catch (notesError) {
          console.error('Error loading notes data:', notesError);
          this.showWarning('Could not load recent notes');
          this.recentNotes = [];
        }
      } catch (error) {
        console.error('Error loading user data:', error);
        this.error = 'Failed to load user data';
        this.showError('Failed to load user data');

        // If token is invalid, redirect to login
        if (error.message.includes('token') || error.response?.status === 401) {
          localStorage.removeItem('token');
          this.$router.push('/login');
        }
      } finally {
        this.loading = false;
      }
    },
    logout() {
      // Clear authentication token
      localStorage.removeItem('token');
      // Redirect to login
      this.$router.push('/login');
    },
    // Modal methods
    openAudioModal() {
      this.showAudioModal = true;
      this.resetAudioState();
    },
    closeAudioModal() {
      this.showAudioModal = false;
      this.stopRecording();
      this.resetAudioState();
    },
    openYouTubeModal() {
      this.showYouTubeModal = true;
      this.youtubeUrl = '';
    },
    closeYouTubeModal() {
      this.showYouTubeModal = false;
      this.youtubeUrl = '';
    },
    openDocumentModal() {
      this.showDocumentModal = true;
      this.selectedDocumentFile = null;
    },
    closeDocumentModal() {
      this.showDocumentModal = false;
      this.selectedDocumentFile = null;
    },
    // Audio recording methods
    async startRecording() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          audio: true
        });
        this.mediaRecorder = new MediaRecorder(stream);
        const audioChunks = [];
        this.mediaRecorder.ondataavailable = event => {
          audioChunks.push(event.data);
        };
        this.mediaRecorder.onstop = () => {
          this.audioBlob = new Blob(audioChunks, {
            type: 'audio/wav'
          });
          stream.getTracks().forEach(track => track.stop());
        };
        this.mediaRecorder.start();
        this.isRecording = true;
        this.recordingTime = 0;
        this.recordingTimer = setInterval(() => {
          this.recordingTime++;
        }, 1000);
      } catch (error) {
        console.error('Error starting recording:', error);
        this.showError('Could not access microphone');
      }
    },
    stopRecording() {
      if (this.mediaRecorder && this.isRecording) {
        this.mediaRecorder.stop();
        this.isRecording = false;
        if (this.recordingTimer) {
          clearInterval(this.recordingTimer);
          this.recordingTimer = null;
        }
      }
    },
    playRecording() {
      if (this.audioBlob) {
        const audio = new Audio(URL.createObjectURL(this.audioBlob));
        audio.play();
      }
    },
    resetAudioState() {
      this.selectedAudioFile = null;
      this.audioBlob = null;
      this.recordingTime = 0;
      this.isDragOver = false;
    },
    // File handling methods
    triggerAudioFileInput() {
      this.$refs.audioFileInput.click();
    },
    handleAudioFileSelect(event) {
      const file = event.target.files[0];
      if (file) {
        this.selectedAudioFile = file;
      }
    },
    handleAudioDrop(event) {
      event.preventDefault();
      this.isDragOver = false;
      const files = event.dataTransfer.files;
      if (files.length > 0) {
        const file = files[0];
        if (file.type.startsWith('audio/')) {
          this.selectedAudioFile = file;
        } else {
          this.showError('Please select an audio file');
        }
      }
    },
    triggerDocumentFileInput() {
      this.$refs.documentFileInput.click();
    },
    handleDocumentFileSelect(event) {
      const file = event.target.files[0];
      if (file) {
        this.selectedDocumentFile = file;
      }
    },
    handleDocumentDrop(event) {
      event.preventDefault();
      this.isDragOverDoc = false;
      const files = event.dataTransfer.files;
      if (files.length > 0) {
        const file = files[0];
        const allowedTypes = ['.pdf', '.doc', '.docx', '.ppt', '.pptx'];
        const fileExtension = '.' + file.name.split('.').pop().toLowerCase();
        if (allowedTypes.includes(fileExtension)) {
          this.selectedDocumentFile = file;
        } else {
          this.showError('Please select a PDF, DOC, or PPT file');
        }
      }
    },
    // Processing methods
    async processAudio() {
      try {
        this.showProcessingModal = true;
        this.processingMessage = 'Transcribing audio content...';
        this.processingProgress = 25;

        // Simulate processing steps
        setTimeout(() => {
          this.processingMessage = 'Analyzing content with AI...';
          this.processingProgress = 50;
        }, 1000);
        setTimeout(() => {
          this.processingMessage = 'Generating study notes...';
          this.processingProgress = 75;
        }, 2000);

        // Create a note from audio processing
        const audioSource = this.selectedAudioFile ? this.selectedAudioFile.name : 'Voice Recording';
        const noteData = {
          title: `Audio Notes - ${audioSource}`,
          content: 'AI-generated notes from audio content will appear here. This is a placeholder for the actual AI processing.',
          category: 'Audio',
          source: 'audio',
          userId: this.userId
        };
        setTimeout(async () => {
          try {
            const newNote = await createNote(noteData);
            this.processingProgress = 100;
            this.processingMessage = 'Notes created successfully!';
            setTimeout(() => {
              this.showProcessingModal = false;
              this.closeAudioModal();
              this.showSuccess('Audio processed and notes created!');
              this.loadUserData(); // Refresh notes
            }, 1000);
          } catch (error) {
            console.error('Error creating note:', error);
            this.showProcessingModal = false;
            this.showError('Failed to create notes from audio');
          }
        }, 3000);
      } catch (error) {
        console.error('Error processing audio:', error);
        this.showProcessingModal = false;
        this.showError('Failed to process audio');
      }
    },
    async processYouTube() {
      try {
        this.showProcessingModal = true;
        this.processingMessage = 'Fetching YouTube video content...';
        this.processingProgress = 25;
        setTimeout(() => {
          this.processingMessage = 'Extracting key information...';
          this.processingProgress = 50;
        }, 1000);
        setTimeout(() => {
          this.processingMessage = 'Generating study notes...';
          this.processingProgress = 75;
        }, 2000);
        const noteData = {
          title: `YouTube Notes - ${this.extractVideoTitle(this.youtubeUrl)}`,
          content: 'AI-generated notes from YouTube video content will appear here. This is a placeholder for the actual AI processing.',
          category: 'Video',
          source: 'youtube',
          sourceUrl: this.youtubeUrl,
          userId: this.userId
        };
        setTimeout(async () => {
          try {
            const newNote = await createNote(noteData);
            this.processingProgress = 100;
            this.processingMessage = 'Notes created successfully!';
            setTimeout(() => {
              this.showProcessingModal = false;
              this.closeYouTubeModal();
              this.showSuccess('YouTube video processed and notes created!');
              this.loadUserData(); // Refresh notes
            }, 1000);
          } catch (error) {
            console.error('Error creating note:', error);
            this.showProcessingModal = false;
            this.showError('Failed to create notes from YouTube video');
          }
        }, 3000);
      } catch (error) {
        console.error('Error processing YouTube:', error);
        this.showProcessingModal = false;
        this.showError('Failed to process YouTube video');
      }
    },
    async processDocument() {
      try {
        this.showProcessingModal = true;
        this.processingMessage = 'Reading document content...';
        this.processingProgress = 25;
        setTimeout(() => {
          this.processingMessage = 'Analyzing document structure...';
          this.processingProgress = 50;
        }, 1000);
        setTimeout(() => {
          this.processingMessage = 'Generating study notes...';
          this.processingProgress = 75;
        }, 2000);
        const noteData = {
          title: `Document Notes - ${this.selectedDocumentFile.name}`,
          content: 'AI-generated notes from document content will appear here. This is a placeholder for the actual AI processing.',
          category: 'Document',
          source: 'document',
          fileName: this.selectedDocumentFile.name,
          userId: this.userId
        };
        setTimeout(async () => {
          try {
            const newNote = await createNote(noteData);
            this.processingProgress = 100;
            this.processingMessage = 'Notes created successfully!';
            setTimeout(() => {
              this.showProcessingModal = false;
              this.closeDocumentModal();
              this.showSuccess('Document processed and notes created!');
              this.loadUserData(); // Refresh notes
            }, 1000);
          } catch (error) {
            console.error('Error creating note:', error);
            this.showProcessingModal = false;
            this.showError('Failed to create notes from document');
          }
        }, 3000);
      } catch (error) {
        console.error('Error processing document:', error);
        this.showProcessingModal = false;
        this.showError('Failed to process document');
      }
    },
    // Utility methods
    isValidYouTubeUrl(url) {
      const youtubeRegex = /^(https?\:\/\/)?(www\.)?(youtube\.com|youtu\.be)\/.+/;
      return youtubeRegex.test(url);
    },
    extractVideoTitle(url) {
      // Extract video ID and create a basic title
      const videoId = this.extractVideoId(url);
      return videoId ? `Video ${videoId}` : 'YouTube Video';
    },
    extractVideoId(url) {
      const match = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\n?#]+)/);
      return match ? match[1] : null;
    },
    getFileIcon(fileName) {
      const extension = fileName.split('.').pop().toLowerCase();
      const iconMap = {
        'pdf': 'fas fa-file-pdf',
        'doc': 'fas fa-file-word',
        'docx': 'fas fa-file-word',
        'ppt': 'fas fa-file-powerpoint',
        'pptx': 'fas fa-file-powerpoint'
      };
      return iconMap[extension] || 'fas fa-file';
    },
    formatFileSize(bytes) {
      if (bytes === 0) return '0 Bytes';
      const k = 1024;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    },
    // Note-related methods
    openNote(noteId) {
      this.$router.push(`/notes/${noteId}`);
    },
    async toggleNoteFavorite(note) {
      try {
        const {
          toggleNoteFavorite
        } = await import('../../api/Note.js');
        const updatedNote = await toggleNoteFavorite(note.id);
        note.isFavorite = updatedNote.isFavorite;
      } catch (error) {
        console.error('Error toggling note favorite:', error);
        note.isFavorite = !note.isFavorite;
      }
    },
    truncateNoteContent(content) {
      return content.length > 80 ? content.substring(0, 80) + '...' : content;
    },
    formatNoteDate(date) {
      return new Date(date).toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric'
      });
    }
  }
};
